mapper.select:
/*AdminMng_SQL.selectAdminNoticeTotalCount*/ SELECT COUNT(*) FROM TB_NOTICE_INFO WHERE 1=1 AND NOTICE_DEL_YN = 'N'
AND A.NOTICE_TITLE LIKE CONCAT('%', #{searchTxt}, '%')
AND A.REG_ID LIKE CONCAT('%', #{searchTxt}, '%')

/*AdminMng_SQL.selectAdminNotice*/ SELECT A.NOTICE_ID , A.NOTICE_TITLE , A.NOTICE_CN , A.NOTICE_FIX_YN , A.NOTICE_LIMIT_YN , A.NOTICE_STR_DT , A.NOTICE_END_DT , A.NOTICE_FINISH_YN , A.NOTICE_DEL_YN , A.NOTICE_POP_YN , A.REG_ID , A.REG_DT , A.UPD_ID , A.UPD_DT FROM TB_NOTICE_INFO A WHERE 1=1 AND A.NOTICE_DEL_YN = 'N'
AND A.NOTICE_TITLE LIKE CONCAT('%', #{searchTxt}, '%')
AND A.REG_ID LIKE CONCAT('%', #{searchTxt}, '%')
ORDER BY A.UPD_DT DESC LIMIT #{perPage} OFFSET #{startRow}

mapper.insert:
		/*AdminMng_SQL.insertAdminNotice*/
	    INSERT INTO TB_NOTICE_INFO (
	        NOTICE_ID
	      , NOTICE_TITLE
	      , NOTICE_CN
	      , NOTICE_FIX_YN
	      , NOTICE_LIMIT_YN
	      , NOTICE_STR_DT
	      , NOTICE_END_DT
	      , NOTICE_FINISH_YN
	      , NOTICE_DEL_YN
	      , NOTICE_POP_YN
	      , REG_ID
	      , REG_DT
	      , UPD_ID
	      , UPD_DT
	    ) VALUES (
            #{noticeId} 
          , #{noticeTitle}
          , #{noticeCn}
          , #{noticeFixYn}
          , #{noticeLimitYn}
          , #{noticeStrDt}
          , #{noticeEndDt}
       	  , 'N'
       	  , 'N'
       	  , #{noticePopYn}
          , #{regId}
          , NOW()
          , #{updId}
          , NOW()
	    )

		/*AdminMng_SQL.insertAdminFile*/
    	INSERT INTO TB_FILE_INFO (
    		FILE_ID
      	  , FILE_ORG_NM
          , FILE_NM
          , FILE_PATH
       	  , FILE_SIZE
          , FILE_EXT
          , REF_TYPE
          , REF_ID
          , FILE_THUMB_NM
          , FILE_THUMB_PATH
          , REG_ID
          , REG_DT
          , UPD_ID
          , UPD_DT
	    ) VALUES (
            #{fileId}
          , #{fileOrgNm}
	      , #{fileNm}
	      , #{filePath}
	      , #{fileSize}
	      , #{fileExt}
	      , #{refType}
	      , #{refId}
	      , #{fileThumbNm}	      
	      , #{fileThumbPath}	      
	      , #{regId}
	      , NOW()
	      , #{updId}
	      , NOW()
	    )
